    35→export class AuthController {
    36→	constructor(private readonly authService: AuthService) {}
    37→
    38→	@Public()
    39→	@Get('github')
    40→	@ApiOperation({ summary: 'Initiate GitHub OAuth' })
    41→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
    42→	async githubAuth(@Res() reply: FastifyReply): Promise<void> {
    43→		const url = await this.authService.initiateOAuth({ provider: 'github' });
    44→		reply.redirect(url.toString());
    45→	}
    46→
    47→	@Public()
    48→	@Get('github/callback')
    49→	@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
    50→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
    51→	async githubCallback(
    52→		@Query('code') code: string,
    53→		@Query('state') state: string,
    54→		@Res() reply: FastifyReply,
    55→	): Promise<void> {
    56→		const result = await this.authService.handleCallback({
    57→			provider: 'github',
    58→			code,
    59→			state,
    60→		});
    61→		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
    62→		if (result.type === 'auth_code') {
    63→			reply.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
    64→		} else {
    65→			reply.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
    66→		}
    67→	}
    68→
    69→	@Public()
    70→	@Get('google')
    71→	@ApiOperation({ summary: 'Initiate Google OAuth' })
    72→	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to Google' })
    73→	async googleAuth(@Res() reply: FastifyReply): Promise<void> {
    74→		const url = await this.authService.initiateOAuth({ provider: 'google' });
