   100→	@Public()
   101→	@Post('token')
   102→	@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
   103→	@ApiResponse({
   104→		status: HttpStatus.OK,
   105→		description: 'Returns access token, sets refresh cookie',
   106→	})
   107→	async exchangeToken(
   108→		@Body() dto: TokenExchangeDto,
   109→		@Req() request: FastifyRequest,
   110→		@Res() reply: FastifyReply,
   111→	): Promise<void> {
   112→		const result = await this.authService.exchangeCode({
   113→			code: dto.code,
   114→			ip: request.ip,
   115→			userAgent: request.headers['user-agent'] ?? '',
   116→			provider: 'github',
   117→		});
   118→
   119→		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
   120→			httpOnly: true,
   121→			secure: !isDevEnv(),
   122→			sameSite: 'strict',
   123→			path: '/api/auth',
   124→			maxAge: 30 * 24 * 60 * 60,
   125→		});
   126→
   127→		reply.send({ access_token: result.accessToken });
   128→	}
   129→
   130→	@Public()
   131→	@Throttle({ default: { limit: 5, ttl: 60000 } })
   132→	@Post('refresh')
   133→	@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
   134→	@ApiResponse({
   135→		status: HttpStatus.OK,
   136→		description: 'Returns new access token, rotates refresh cookie',
   137→	})
   138→	@ApiResponse({
   139→		status: HttpStatus.UNAUTHORIZED,
   140→		description: 'No or invalid refresh token',
   141→	})
   142→	async refresh(
   143→		@Req() request: FastifyRequest,
   144→		@Res() reply: FastifyReply,
   145→	): Promise<void> {
   146→		const refreshToken = (request.cookies as Record<string, string>)[
   147→			REFRESH_TOKEN_COOKIE_NAME
   148→		];
   149→		if (!refreshToken) throw new UnauthorizedException('No refresh token');
   150→
   151→		const result = await this.authService.refreshTokens({ refreshToken });
   152→
   153→		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
   154→			httpOnly: true,
   155→			secure: !isDevEnv(),
   156→			sameSite: 'strict',
   157→			path: '/api/auth',
   158→			maxAge: 30 * 24 * 60 * 60,
   159→		});
   160→
   161→		reply.send({ access_token: result.accessToken });
   162→	}
