   190→		await this.authService.linkAccount({
   191→			linkingToken: dto.linking_token,
   192→			userId: user.user_id,
   193→		});
   194→		return { success: true };
   195→	}
   196→
   197→	@Post('signup/company')
   198→	@ApiOperation({ summary: 'Create a company for the current user' })
   199→	@ApiResponse({
   200→		status: HttpStatus.CREATED,
   201→		description: 'Company created successfully',
   202→	})
   203→	async createCompany(
   204→		@Body() dto: CreateCompanyDto,
   205→		@CurrentUser() user: IRequestUser,
   206→	): Promise<{ company_id: string }> {
   207→		return this.authService.createCompany({
   208→			name: dto.name,
   209→			userId: user.user_id,
   210→			sessionId: user.session_id,
   211→		});
   212→	}
   213→}
