    20→@ApiTags('Users')
    21→@Controller('users')
    22→export class UserController {
    23→	constructor(
    24→		private readonly userService: UserService,
    25→		private readonly companyMemberService: CompanyMemberService,
    26→		private readonly sessionService: SessionService,
    27→	) {}
    28→
    29→	@Get('me')
    30→	@ApiOperation({ summary: 'Get current user profile with memberships' })
    31→	@ApiResponse({
    32→		status: HttpStatus.OK,
    33→		description: 'Returns user profile and memberships',
    34→	})
    35→	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Unauthorized' })
    36→	async getMe(
    37→		@CurrentUser() user: IRequestUser,
    38→	): Promise<{ user: IUserBase | null; memberships: ICompanyMemberBase[] }> {
    39→		const [foundUser, memberships] = await Promise.all([
    40→			this.userService.findById({ userId: user.user_id }),
    41→			this.companyMemberService.findByUserId({ userId: user.user_id }),
    42→		]);
    43→
    44→		return { user: foundUser, memberships };
    45→	}
    46→
    47→	@Post('me/company')
    48→	@ApiOperation({ summary: 'Switch active company context' })
    49→	@ApiResponse({
    50→		status: HttpStatus.OK,
    51→		description: 'Company context updated successfully',
    52→	})
    53→	@ApiResponse({
    54→		status: HttpStatus.FORBIDDEN,
    55→		description: 'Not a member of the company',
    56→	})
    57→	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Unauthorized' })
    58→	async switchCompany(
    59→		@Body() dto: SwitchCompanyDto,
    60→		@CurrentUser() user: IRequestUser,
    61→	): Promise<{ success: boolean }> {
    62→		const membership = await this.companyMemberService.findByUserAndCompany({
    63→			userId: user.user_id,
    64→			companyId: dto.company_id,
    65→		});
    66→
    67→		if (!membership) {
    68→			throw new ForbiddenException('Not a member of this company');
    69→		}
    70→
    71→		await this.sessionService.updateCompanyContext({
    72→			userId: user.user_id,
    73→			sessionId: user.session_id,
    74→			companyId: dto.company_id,
    75→			role: membership.role,
    76→		});
    77→
    78→		return { success: true };
    79→	}
    80→}
