   228→
   229→		const memberships = await this.companyMemberService.findByUserId({ userId: user_id });
   230→		const firstMembership = memberships[0] ?? null;
   231→
   232→		const refreshToken = randomUUID();
   233→		const now = new Date().toISOString();
   234→
   235→		const session: ISession = {
   236→			user_id,
   237→			session_id,
   238→			role: firstMembership ? firstMembership.role : null,
   239→			company_id: firstMembership ? firstMembership.company_id : null,
   240→			provider,
