    19→	async createSession({
    20→		session,
    21→		refreshToken,
    22→	}: {
    23→		session: ISession;
    24→		refreshToken: string;
    25→	}): Promise<void> {
    26→		this.logger.log('Creating session', {
    27→			userId: session.user_id,
    28→			sessionId: session.session_id,
    29→		});
    30→
    31→		const sessionKey = `session:${session.user_id}:${session.session_id}`;
    32→		const sessionSetKey = `sessions:${session.user_id}`;
    33→		const refreshKey = `refresh:${refreshToken}`;
    34→
    35→		const payload: IRefreshToken = {
    36→			user_id: session.user_id,
    37→			session_id: session.session_id,
    38→		};
    39→
    40→		await this.redisWrite
    41→			.multi()
    42→			.set(sessionKey, JSON.stringify(session), 'EX', this.SESSION_TTL)
    43→			.sadd(sessionSetKey, session.session_id)
    44→			.set(refreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
    45→			.exec();
    46→	}
    47→
    48→	async getSession({
    49→		userId,
    50→		sessionId,
    51→	}: {
    52→		userId: string;
    53→		sessionId: string;
    54→	}): Promise<ISession | null> {
    55→		this.logger.log('Getting session', { userId, sessionId });
    56→
    57→		const sessionKey = `session:${userId}:${sessionId}`;
    58→
    59→		let raw: string | null = null;
    60→
    61→		try {
    62→			raw = await this.redisRead.get(sessionKey);
    63→		} catch {
    64→			this.logger.warn('Read replica failed, falling back to write client', {
    65→				userId,
    66→				sessionId,
    67→			});
    68→			raw = await this.redisWrite.get(sessionKey);
    69→		}
    70→
    71→		if (!raw) {
    72→			return null;
    73→		}
    74→
    75→		return JSON.parse(raw) as ISession;
    76→	}
