   103→	async destroySession({
   104→		userId,
   105→		sessionId,
   106→		refreshToken,
   107→	}: {
   108→		userId: string;
   109→		sessionId: string;
   110→		refreshToken?: string;
   111→	}): Promise<void> {
   112→		this.logger.log('Destroying session', { userId, sessionId });
   113→
   114→		const sessionKey = `session:${userId}:${sessionId}`;
   115→		const sessionSetKey = `sessions:${userId}`;
   116→
   117→		const multi = this.redisWrite.multi().del(sessionKey).srem(sessionSetKey, sessionId);
   118→
   119→		if (refreshToken) {
   120→			multi.del(`refresh:${refreshToken}`);
   121→		}
   122→
   123→		await multi.exec();
