     3→	ExecutionContext,
     4→	ForbiddenException,
     5→	Injectable,
     6→} from '@nestjs/common';
     7→import { Reflector } from '@nestjs/core';
     8→
     9→import { ROLES_KEY } from '@modules/auth/decorators/roles.decorator';
    10→import { IRequestUser } from '@modules/auth/types/auth.interface';
    11→
    12→import type { FastifyRequest } from 'fastify';
    13→
    14→@Injectable()
    15→export class RolesGuard implements CanActivate {
    16→	constructor(private readonly reflector: Reflector) {}
    17→
    18→	canActivate(context: ExecutionContext): boolean {
    19→		const requiredRoles = this.reflector.getAllAndOverride<('admin' | 'member')[]>(
    20→			ROLES_KEY,
    21→			[context.getHandler(), context.getClass()],
    22→		);
    23→
    24→		// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    25→		if (!requiredRoles || requiredRoles.length === 0) return true;
    26→
    27→		const request = context
    28→			.switchToHttp()
    29→			.getRequest<FastifyRequest & { user?: IRequestUser }>();
    30→		const user = request.user;
    31→
    32→		if (!user) throw new ForbiddenException();
    33→		if (!user.role) throw new ForbiddenException();
    34→		if (!requiredRoles.includes(user.role)) throw new ForbiddenException();
    35→
    36→		return true;
    37→	}
    38→}
