    10→	GITHUB_CLIENT_SECRET,
    11→} from '@constants/env-variables.constant';
    12→
    13→@Injectable()
    14→export class GithubStrategy {
    15→	private readonly github: GitHub;
    16→	private readonly logger = new Logger(GithubStrategy.name);
    17→
    18→	constructor(private readonly configService: EnvConfigService) {
    19→		const clientId = this.configService.get<string>({ key: GITHUB_CLIENT_ID });
    20→		const clientSecret = this.configService.get<string>({ key: GITHUB_CLIENT_SECRET });
    21→		const callbackUrl = this.configService.get<string>({ key: GITHUB_CALLBACK_URL });
    22→
    23→		this.github = new GitHub(clientId, clientSecret, callbackUrl);
    24→	}
    25→
    26→	createAuthorizationURL({ state }: { state: string; codeVerifier: string }): URL {
    27→		return this.github.createAuthorizationURL(state, ['user:email']);
    28→	}
    29→
    30→	async validateAuthorizationCode({
    31→		code,
    32→	}: {
    33→		code: string;
    34→		codeVerifier: string;
    35→	}): Promise<{ accessToken: string }> {
    36→		const tokens = await this.github.validateAuthorizationCode(code);
    37→		return { accessToken: tokens.accessToken() };
    38→	}
    39→
    40→	async getUserProfile({ accessToken }: { accessToken: string }): Promise<IOAuthProfile> {
    41→		try {
    42→			const response = await fetch('https://api.github.com/user', {
    43→				headers: {
    44→					Authorization: `Bearer ${accessToken}`,
    45→					Accept: 'application/json',
    46→				},
    47→			});
    48→
    49→			if (!response.ok) {
    50→				throw new Error(`GitHub API returned ${response.status}`);
    51→			}
    52→
    53→			const data = (await response.json()) as {
    54→				id: number;
    55→				email: string | null;
    56→				name: string | null;
    57→				avatar_url: string | null;
    58→				login: string;
    59→			};
    60→
    61→			let email = data.email;
    62→
    63→			if (!email) {
    64→				const emailsResponse = await fetch('https://api.github.com/user/emails', {
    65→					headers: {
    66→						Authorization: `Bearer ${accessToken}`,
    67→						Accept: 'application/json',
    68→					},
    69→				});
    70→
    71→				if (!emailsResponse.ok) {
    72→					throw new Error(`GitHub emails API returned ${emailsResponse.status}`);
    73→				}
    74→
    75→				const emails = (await emailsResponse.json()) as {
    76→					email: string;
    77→					primary: boolean;
    78→					verified: boolean;
    79→				}[];
    80→
    81→				const primaryEmail = emails.find((e) => e.primary && e.verified);
    82→				email = primaryEmail?.email ?? null;
    83→			}
    84→
    85→			return {
    86→				provider: 'github',
    87→				provider_id: String(data.id),
    88→				email: email ?? '',
    89→				name: data.name,
    90→				avatar_url: data.avatar_url,
    91→			};
    92→		} catch (error) {
    93→			this.logger.error('Failed to fetch GitHub user profile', error);
    94→			throw error;
    95→		}
    96→	}
    97→}
