     2→
     3→import { Injectable, Logger } from '@nestjs/common';
     4→import { plainToInstance } from 'class-transformer';
     5→import { validate, ValidationError } from 'class-validator';
     6→import { Knex } from 'knex';
     7→import { InjectConnection } from 'nest-knexjs';
     8→
     9→import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
    10→import { InvitationBaseDto } from '@modules/invitation/dto/invitation.base.dto';
    11→import { IInvitationBase } from '@modules/invitation/types/invitation.base.interface';
    12→import { IInvitationCreate } from '@modules/invitation/types/invitation.create.interface';
    13→
    14→import { TABLE_NAME_INVITATIONS } from '@constants/db.constant';
    15→
    16→const INVITATION_EXPIRY_MS = 72 * 60 * 60 * 1000;
    17→
    18→@Injectable()
    19→export class InvitationModel {
    20→	private readonly logger = new Logger(InvitationModel.name);
    21→	private readonly tableName = TABLE_NAME_INVITATIONS;
    22→
    23→	constructor(
    24→		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
    25→		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
    26→	) {}
    27→
    28→	async findByToken({ token }: { token: string }): Promise<IInvitationBase | null> {
    29→		try {
    30→			const result = await this.knexRead<IInvitationBase>(this.tableName)
    31→				.where({ token })
    32→				.whereNull('accepted_at')
    33→				.whereNull('deleted_at')
    34→				.where('expires_at', '>', this.knexRead.fn.now())
    35→				.first();
    36→
    37→			if (!result) {
    38→				return null;
    39→			}
    40→
    41→			const dto = plainToInstance(InvitationBaseDto, result);
    42→			const errors = await validate(dto, { skipMissingProperties: true });
    43→			if (errors.length > 0) {
    44→				this.logger.error(
    45→					`Validation failed for invitation data: ${this.formatValidationErrors({ errors })}`,
    46→				);
    47→				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
    48→			}
    49→
    50→			return result;
    51→		} catch (error) {
    52→			this.logger.error(
    53→				`Failed to find invitation by token: ${(error as Error).message}`,
    54→			);
    55→			throw error;
    56→		}
    57→	}
    58→
    59→	async findPendingByCompanyId({
    60→		companyId,
    61→	}: {
    62→		companyId: IInvitationBase['company_id'];
    63→	}): Promise<IInvitationBase[]> {
    64→		try {
    65→			const results = await this.knexRead<IInvitationBase>(this.tableName)
    66→				.where({ company_id: companyId })
    67→				.whereNull('accepted_at')
    68→				.whereNull('deleted_at')
    69→				.where('expires_at', '>', this.knexRead.fn.now());
    70→
    71→			return results;
    72→		} catch (error) {
    73→			this.logger.error(
    74→				`Failed to find pending invitations for company ${companyId}: ${(error as Error).message}`,
    75→			);
    76→			throw error;
    77→		}
    78→	}
    79→
    80→	async create({ data }: { data: IInvitationCreate }): Promise<IInvitationBase> {
    81→		try {
    82→			const token = randomBytes(48).toString('base64url');
    83→			const expiresAt = new Date(Date.now() + INVITATION_EXPIRY_MS);
    84→
    85→			const _id = randomUUID();
    86→			const [created] = await this.knexWrite<IInvitationBase>(this.tableName)
    87→				.insert({
    88→					_id,
    89→					...data,
    90→					token,
    91→					expires_at: expiresAt,
    92→					accepted_at: null,
    93→					created_at: this.knexWrite.fn.now(),
    94→					updated_at: this.knexWrite.fn.now(),
    95→				})
    96→				.returning('*');
    97→
    98→			if (!created) {
    99→				throw new Error('Failed to create invitation');
   100→			}
   101→
   102→			this.logger.debug(`Created invitation with id ${_id}`);
   103→			return created;
   104→		} catch (error) {
   105→			this.logger.error(`Failed to create invitation: ${(error as Error).message}`);
   106→			throw error;
   107→		}
   108→	}
   109→
   110→	async markAccepted({
   111→		invitationId,
   112→	}: {
   113→		invitationId: IInvitationBase['_id'];
   114→	}): Promise<void> {
   115→		try {
   116→			await this.knexWrite<IInvitationBase>(this.tableName)
   117→				.where({ _id: invitationId })
   118→				.update({
   119→					accepted_at: this.knexWrite.fn.now(),
   120→					updated_at: this.knexWrite.fn.now(),
   121→				});
   122→
   123→			this.logger.debug(`Marked invitation ${invitationId} as accepted`);
   124→		} catch (error) {
   125→			this.logger.error(
   126→				`Failed to mark invitation ${invitationId} as accepted: ${(error as Error).message}`,
   127→			);
   128→			throw error;
   129→		}
   130→	}
   131→
   132→	async softDelete({
   133→		invitationId,
   134→	}: {
   135→		invitationId: IInvitationBase['_id'];
   136→	}): Promise<void> {
   137→		try {
   138→			await this.knexWrite<IInvitationBase>(this.tableName)
   139→				.where({ _id: invitationId })
   140→				.whereNull('deleted_at')
   141→				.update({
   142→					deleted_at: this.knexWrite.fn.now(),
   143→					updated_at: this.knexWrite.fn.now(),
   144→				});
   145→
   146→			this.logger.debug(`Soft deleted invitation ${invitationId}`);
   147→		} catch (error) {
   148→			this.logger.error(
   149→				`Failed to soft delete invitation ${invitationId}: ${(error as Error).message}`,
   150→			);
   151→			throw error;
   152→		}
   153→	}
   154→
   155→	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
   156→		return errors
   157→			.map(
   158→				(error) =>
   159→					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
   160→			)
   161→			.join('; ');
   162→	}
   163→}
