import { randomUUID } from 'crypto';

import { Redis } from 'ioredis';
import * as jwt from 'jsonwebtoken';
import Knex from 'knex';

import { ISession } from '@modules/session/types/session.interface';

const JWT_SECRET = 'test-jwt-secret-at-least-32-characters-long';
const SESSION_TTL = 30 * 24 * 60 * 60;

export interface ITestUser {
	_id: string;
	email: string;
	name: string | null;
	avatar_url: string | null;
}

export interface ITestSession {
	userId: string;
	sessionId: string;
	refreshToken: string;
}

export interface ITestAuthResult {
	user: ITestUser;
	accessToken: string;
	session: ITestSession;
}

export interface ITestAdminAuthResult extends ITestAuthResult {
	companyId: string;
}

export function createTestUser({ email }: { email: string }): ITestUser {
	return {
		_id: randomUUID(),
		email,
		name: 'Test User',
		avatar_url: null,
	};
}

export async function insertUser({
	knex,
	user,
}: {
	knex: Knex.Knex;
	user: ITestUser;
}): Promise<ITestUser> {
	await knex('users').insert({
		_id: user._id,
		email: user.email,
		name: user.name,
		avatar_url: user.avatar_url,
		created_at: knex.fn.now(),
		updated_at: knex.fn.now(),
	});
	return user;
}

export async function insertCompany({
	knex,
	name,
}: {
	knex: Knex.Knex;
	name: string;
}): Promise<{ _id: string; name: string }> {
	const _id = randomUUID();
	await knex('companies').insert({
		_id,
		name,
		created_at: knex.fn.now(),
		updated_at: knex.fn.now(),
	});
	return { _id, name };
}

export async function insertCompanyMember({
	knex,
	userId,
	companyId,
	role,
}: {
	knex: Knex.Knex;
	userId: string;
	companyId: string;
	role: 'admin' | 'member';
}): Promise<void> {
	await knex('company_members').insert({
		_id: randomUUID(),
		user_id: userId,
		company_id: companyId,
		role,
		created_at: knex.fn.now(),
		updated_at: knex.fn.now(),
	});
}

export function createAccessToken({
	userId,
	sessionId,
	role,
	companyId,
}: {
	userId: string;
	sessionId: string;
	role: 'admin' | 'member' | null;
	companyId: string | null;
}): string {
	return jwt.sign(
		{ user_id: userId, session_id: sessionId, role, company_id: companyId },
		JWT_SECRET,
		{ expiresIn: 3600 },
	);
}

export async function createSession({
	redis,
	userId,
	sessionId,
	role,
	companyId,
}: {
	redis: Redis;
	userId: string;
	sessionId: string;
	role: 'admin' | 'member' | null;
	companyId: string | null;
}): Promise<string> {
	const refreshToken = randomUUID();
	const now = new Date().toISOString();

	const session: ISession = {
		user_id: userId,
		session_id: sessionId,
		role,
		company_id: companyId,
		provider: 'github',
		ip: '127.0.0.1',
		user_agent: 'test-agent',
		created_at: now,
		last_active: now,
	};

	const payload = { user_id: userId, session_id: sessionId };

	await redis
		.multi()
		.set(`session:${userId}:${sessionId}`, JSON.stringify(session), 'EX', SESSION_TTL)
		.sadd(`sessions:${userId}`, sessionId)
		.set(`refresh:${refreshToken}`, JSON.stringify(payload), 'EX', SESSION_TTL)
		.exec();

	return refreshToken;
}

export async function setupTestUser({
	knex,
	redis,
	email,
	role,
	companyId,
}: {
	knex: Knex.Knex;
	redis: Redis;
	email: string;
	role: 'admin' | 'member' | null;
	companyId: string | null;
}): Promise<ITestAuthResult> {
	const user = createTestUser({ email });
	await insertUser({ knex, user });

	const sessionId = randomUUID();
	const refreshToken = await createSession({
		redis,
		userId: user._id,
		sessionId,
		role,
		companyId,
	});

	const accessToken = createAccessToken({
		userId: user._id,
		sessionId,
		role,
		companyId,
	});

	return {
		user,
		accessToken,
		session: { userId: user._id, sessionId, refreshToken },
	};
}

export async function cleanDatabase({ knex }: { knex: Knex.Knex }): Promise<void> {
	await knex('invitations').delete();
	await knex('company_members').delete();
	await knex('oauth_accounts').delete();
	await knex('companies').delete();
	await knex('users').delete();
}

export async function cleanRedis({ redis }: { redis: Redis }): Promise<void> {
	await redis.flushdb();
}

import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { ValidationPipe } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import type { App } from 'supertest/types';

import { AppModule } from '@modules/app/app.module';
import { REFRESH_TOKEN_COOKIE_NAME } from '@modules/auth/constants/auth.constant';
import { GithubStrategy } from '@modules/auth/strategies/github.strategy';
import { GoogleStrategy } from '@modules/auth/strategies/google.strategy';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	insertCompany,
	insertCompanyMember,
	insertUser,
	createTestUser,
} from './helpers/auth.helper';

describe('AuthModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;

	beforeAll(async () => {
		const moduleFixture: TestingModule = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL'],
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanRedis({ redis });
	});

	describe('GET /api/auth/github', () => {
		it('should redirect to GitHub OAuth URL', async () => {
			const response = await request(httpServer).get('/api/auth/github').expect(302);

			expect(response.headers['location']).toContain('github.com');
		});
	});

	describe('GET /api/auth/google', () => {
		it('should redirect to Google OAuth URL', async () => {
			const response = await request(httpServer).get('/api/auth/google').expect(302);

			expect(response.headers['location']).toContain('accounts.google.com');
		});
	});

	describe('GET /api/auth/github/callback', () => {
		it('should return 401 when state is invalid', async () => {
			await request(httpServer)
				.get('/api/auth/github/callback?code=someCode&state=invalidState')
				.expect(401);
		});

		it('should handle OAuth callback for new user and redirect with auth code', async () => {
			const githubStrategy = app.get(GithubStrategy);

			const state = randomUUID();
			const codeVerifier = 'test-verifier';
			await redis.set(
				`oauth_state:${state}`,
				JSON.stringify({ codeVerifier, provider: 'github' }),
				'EX',
				600,
			);

			const mockProfile = {
				provider: 'github' as const,
				provider_id: `github-${randomUUID()}`,
				email: `newuser-${randomUUID()}@example.com`,
				name: 'New User',
				avatar_url: null,
			};

			jest.spyOn(githubStrategy, 'validateAuthorizationCode').mockResolvedValueOnce({
				accessToken: 'mock-access-token',
			});
			jest.spyOn(githubStrategy, 'getUserProfile').mockResolvedValueOnce(mockProfile);

			const response = await request(httpServer)
				.get(`/api/auth/github/callback?code=testcode&state=${state}`)
				.expect(302);

			expect(response.headers['location']).toContain('/auth/callback?code=');
		});

		it('should redirect with linking token when email already exists', async () => {
			const githubStrategy = app.get(GithubStrategy);

			const state = randomUUID();
			await redis.set(
				`oauth_state:${state}`,
				JSON.stringify({ codeVerifier: 'verifier', provider: 'github' }),
				'EX',
				600,
			);

			const user = createTestUser({ email: `existing-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			jest.spyOn(githubStrategy, 'validateAuthorizationCode').mockResolvedValueOnce({
				accessToken: 'mock-access-token',
			});
			jest.spyOn(githubStrategy, 'getUserProfile').mockResolvedValueOnce({
				provider: 'github',
				provider_id: `new-provider-id-${randomUUID()}`,
				email: user.email,
				name: 'Existing User',
				avatar_url: null,
			});

			const response = await request(httpServer)
				.get(`/api/auth/github/callback?code=testcode&state=${state}`)
				.expect(302);

			expect(response.headers['location']).toContain('/auth/link?linking_token=');
		});
	});

	describe('GET /api/auth/google/callback', () => {
		it('should return 401 when state is invalid', async () => {
			await request(httpServer)
				.get('/api/auth/google/callback?code=someCode&state=invalidState')
				.expect(401);
		});

		it('should handle OAuth callback for new user and redirect with auth code', async () => {
			const googleStrategy = app.get(GoogleStrategy);

			const state = randomUUID();
			await redis.set(
				`oauth_state:${state}`,
				JSON.stringify({ codeVerifier: 'test-verifier', provider: 'google' }),
				'EX',
				600,
			);

			const mockProfile = {
				provider: 'google' as const,
				provider_id: `google-${randomUUID()}`,
				email: `googleuser-${randomUUID()}@example.com`,
				name: 'Google User',
				avatar_url: null,
			};

			jest.spyOn(googleStrategy, 'validateAuthorizationCode').mockResolvedValueOnce({
				accessToken: 'mock-google-access-token',
			});
			jest.spyOn(googleStrategy, 'getUserProfile').mockResolvedValueOnce(mockProfile);

			const response = await request(httpServer)
				.get(`/api/auth/google/callback?code=testcode&state=${state}`)
				.expect(302);

			expect(response.headers['location']).toContain('/auth/callback?code=');
		});
	});

	describe('POST /api/auth/token', () => {
		it('should exchange valid auth code for tokens', async () => {
			const userId = randomUUID();
			const sessionId = randomUUID();
			const authCode = randomUUID();

			await knex('users').insert({
				_id: userId,
				email: `tokentest-${randomUUID()}@example.com`,
				name: 'Token Test User',
				avatar_url: null,
				created_at: knex.fn.now(),
				updated_at: knex.fn.now(),
			});

			await redis.set(
				`auth_code:${authCode}`,
				JSON.stringify({ user_id: userId, session_id: sessionId }),
				'EX',
				60,
			);

			const response = await request(httpServer)
				.post('/api/auth/token')
				.send({ code: authCode })
				.expect(200);

			expect(response.body).toHaveProperty('access_token');
			expect(response.headers['set-cookie']).toBeDefined();
		});

		it('should return 401 for invalid auth code', async () => {
			await request(httpServer)
				.post('/api/auth/token')
				.send({ code: 'invalid-code' })
				.expect(401);
		});
	});

	describe('POST /api/auth/refresh', () => {
		it('should return new tokens with valid refresh cookie', async () => {
			const user = createTestUser({ email: `refresh-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const sessionId = randomUUID();
			const refreshToken = await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const response = await request(httpServer)
				.post('/api/auth/refresh')
				.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
				.expect(200);

			expect(response.body).toHaveProperty('access_token');
			expect(response.headers['set-cookie']).toBeDefined();
		});

		it('should return 401 when no refresh cookie is present', async () => {
			await request(httpServer).post('/api/auth/refresh').expect(401);
		});

		it('should return 401 for invalid refresh token', async () => {
			await request(httpServer)
				.post('/api/auth/refresh')
				.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=invalid-token`)
				.expect(401);
		});

		it('should return 401 and destroy session when reusing a rotated refresh token', async () => {
			const user = createTestUser({ email: `reuse-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const sessionId = randomUUID();
			const refreshToken = await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const firstRefreshResponse = await request(httpServer)
				.post('/api/auth/refresh')
				.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
				.expect(200);

			expect(firstRefreshResponse.body).toHaveProperty('access_token');

			await request(httpServer)
				.post('/api/auth/refresh')
				.set('Cookie', `${REFRESH_TOKEN_COOKIE_NAME}=${refreshToken}`)
				.expect(401);

			const sessionData = await redis.get(`session:${user._id}:${sessionId}`);
			expect(sessionData).toBeNull();
		});
	});

	describe('POST /api/auth/logout', () => {
		it('should return 200 and destroy session', async () => {
			const user = createTestUser({ email: `logout-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: null,
				companyId: null,
			});

			const response = await request(httpServer)
				.post('/api/auth/logout')
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(200);

			expect(response.body).toEqual({ success: true });

			const sessionData = await redis.get(`session:${user._id}:${sessionId}`);
			expect(sessionData).toBeNull();
		});

		it('should return 401 when unauthenticated', async () => {
			await request(httpServer).post('/api/auth/logout').expect(401);
		});
	});

	describe('POST /api/auth/logout/all', () => {
		it('should return 200 and destroy all sessions', async () => {
			const user = createTestUser({ email: `logoutall-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const sessionId1 = randomUUID();
			const sessionId2 = randomUUID();

			await createSession({
				redis,
				userId: user._id,
				sessionId: sessionId1,
				role: null,
				companyId: null,
			});

			await createSession({
				redis,
				userId: user._id,
				sessionId: sessionId2,
				role: null,
				companyId: null,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId: sessionId1,
				role: null,
				companyId: null,
			});

			const response = await request(httpServer)
				.post('/api/auth/logout/all')
				.set('Authorization', `Bearer ${accessToken}`)
				.expect(200);

			expect(response.body).toEqual({ success: true });

